const path = require('path');

const files = {
  "src/controllers/authController.js": "const bcrypt = require('bcryptjs');\nconst jwt = require('jsonwebtoken');\nconst { query } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\n\nconst generateToken = (user) =>\n  jwt.sign(\n    { id: user.id, email: user.email, role: user.role, name: user.name },\n    process.env.JWT_SECRET,\n    { expiresIn: process.env.JWT_EXPIRES_IN || '8h' }\n  );\n\n// POST /api/auth/register\nconst register = asyncHandler(async (req, res) => {\n  const { name, email, password, role, manager_id, department } = req.body;\n\n  if (!['employee', 'manager', 'admin'].includes(role)) {\n    return res.status(400).json({ error: 'Invalid role. Must be employee, manager, or admin.' });\n  }\n\n  const existing = await query('SELECT id FROM users WHERE email = $1', [email]);\n  if (existing.rows.length > 0) {\n    return res.status(409).json({ error: 'Email already registered.' });\n  }\n\n  const password_hash = await bcrypt.hash(password, 12);\n\n  const result = await query(\n    `INSERT INTO users (name, email, password_hash, role, manager_id, department)\n     VALUES ($1, $2, $3, $4, $5, $6)\n     RETURNING id, name, email, role, department, created_at`,\n    [name, email, password_hash, role, manager_id || null, department || null]\n  );\n\n  const user = result.rows[0];\n  res.status(201).json({ user, token: generateToken(user) });\n});\n\n// POST /api/auth/login\nconst login = asyncHandler(async (req, res) => {\n  const { email, password } = req.body;\n\n  const result = await query(\n    'SELECT id, name, email, password_hash, role, department, is_active FROM users WHERE email = $1',\n    [email]\n  );\n\n  const user = result.rows[0];\n  if (!user || !user.is_active) {\n    return res.status(401).json({ error: 'Invalid credentials or account inactive.' });\n  }\n\n  const valid = await bcrypt.compare(password, user.password_hash);\n  if (!valid) {\n    return res.status(401).json({ error: 'Invalid credentials.' });\n  }\n\n  const { password_hash, ...safeUser } = user;\n  res.json({ user: safeUser, token: generateToken(safeUser) });\n});\n\n// GET /api/auth/me\nconst me = asyncHandler(async (req, res) => {\n  const result = await query(\n    `SELECT u.id, u.name, u.email, u.role, u.department, u.is_active,\n            m.name AS manager_name, m.email AS manager_email\n     FROM users u\n     LEFT JOIN users m ON m.id = u.manager_id\n     WHERE u.id = $1`,\n    [req.user.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'User not found.' });\n  res.json(result.rows[0]);\n});\n\nmodule.exports = { register, login, me };\n",
  "src/controllers/userController.js": "const { query } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\nconst bcrypt = require('bcryptjs');\n\n// GET /api/users \u2014 Admin: all users; Manager: their direct reports\nconst listUsers = asyncHandler(async (req, res) => {\n  let result;\n  if (req.user.role === 'admin') {\n    result = await query(\n      `SELECT u.id, u.name, u.email, u.role, u.department, u.is_active,\n              m.name AS manager_name\n       FROM users u\n       LEFT JOIN users m ON m.id = u.manager_id\n       ORDER BY u.role, u.name`\n    );\n  } else if (req.user.role === 'manager') {\n    result = await query(\n      `SELECT id, name, email, role, department, is_active\n       FROM users WHERE manager_id = $1 ORDER BY name`,\n      [req.user.id]\n    );\n  } else {\n    return res.status(403).json({ error: 'Access denied.' });\n  }\n  res.json(result.rows);\n});\n\n// GET /api/users/:id\nconst getUser = asyncHandler(async (req, res) => {\n  const result = await query(\n    `SELECT u.id, u.name, u.email, u.role, u.department, u.is_active,\n            u.manager_id, m.name AS manager_name\n     FROM users u\n     LEFT JOIN users m ON m.id = u.manager_id\n     WHERE u.id = $1`,\n    [req.params.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'User not found.' });\n  res.json(result.rows[0]);\n});\n\n// PUT /api/users/:id \u2014 Admin only\nconst updateUser = asyncHandler(async (req, res) => {\n  const { name, role, manager_id, department, is_active } = req.body;\n  const result = await query(\n    `UPDATE users SET name=$1, role=$2, manager_id=$3, department=$4, is_active=$5\n     WHERE id=$6\n     RETURNING id, name, email, role, department, is_active`,\n    [name, role, manager_id || null, department, is_active, req.params.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'User not found.' });\n  res.json(result.rows[0]);\n});\n\n// POST /api/users/:id/reset-password \u2014 Admin only\nconst resetPassword = asyncHandler(async (req, res) => {\n  const { new_password } = req.body;\n  if (!new_password || new_password.length < 6) {\n    return res.status(400).json({ error: 'Password must be at least 6 characters.' });\n  }\n  const hash = await bcrypt.hash(new_password, 12);\n  await query('UPDATE users SET password_hash=$1 WHERE id=$2', [hash, req.params.id]);\n  res.json({ message: 'Password reset successfully.' });\n});\n\n// GET /api/users/managers \u2014 list all managers (for dropdown)\nconst listManagers = asyncHandler(async (req, res) => {\n  const result = await query(\n    `SELECT id, name, email, department FROM users WHERE role IN ('manager','admin') AND is_active=TRUE ORDER BY name`\n  );\n  res.json(result.rows);\n});\n\nmodule.exports = { listUsers, getUser, updateUser, resetPassword, listManagers };\n",
  "src/controllers/cycleController.js": "const { query } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\n\n// \u2500\u2500 GOAL CYCLES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// GET /api/cycles\nconst listCycles = asyncHandler(async (req, res) => {\n  const result = await query('SELECT * FROM goal_cycles ORDER BY start_date DESC');\n  res.json(result.rows);\n});\n\n// GET /api/cycles/active\nconst getActiveCycle = asyncHandler(async (req, res) => {\n  const result = await query('SELECT * FROM goal_cycles WHERE is_active = TRUE LIMIT 1');\n  if (!result.rows[0]) return res.status(404).json({ error: 'No active cycle found.' });\n  res.json(result.rows[0]);\n});\n\n// POST /api/cycles \u2014 Admin only\nconst createCycle = asyncHandler(async (req, res) => {\n  const { name, start_date, end_date, goal_setting_opens, q1_opens, q2_opens, q3_opens, q4_opens } = req.body;\n  const result = await query(\n    `INSERT INTO goal_cycles (name, start_date, end_date, goal_setting_opens, q1_opens, q2_opens, q3_opens, q4_opens, created_by)\n     VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9)\n     RETURNING *`,\n    [name, start_date, end_date, goal_setting_opens, q1_opens, q2_opens, q3_opens, q4_opens, req.user.id]\n  );\n  res.status(201).json(result.rows[0]);\n});\n\n// PUT /api/cycles/:id \u2014 Admin only\nconst updateCycle = asyncHandler(async (req, res) => {\n  const { name, start_date, end_date, goal_setting_opens, q1_opens, q2_opens, q3_opens, q4_opens } = req.body;\n  const result = await query(\n    `UPDATE goal_cycles SET name=$1, start_date=$2, end_date=$3, goal_setting_opens=$4,\n     q1_opens=$5, q2_opens=$6, q3_opens=$7, q4_opens=$8 WHERE id=$9 RETURNING *`,\n    [name, start_date, end_date, goal_setting_opens, q1_opens, q2_opens, q3_opens, q4_opens, req.params.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'Cycle not found.' });\n  res.json(result.rows[0]);\n});\n\n// POST /api/cycles/:id/activate \u2014 Admin only (deactivates all others)\nconst activateCycle = asyncHandler(async (req, res) => {\n  await query('UPDATE goal_cycles SET is_active = FALSE');\n  const result = await query(\n    'UPDATE goal_cycles SET is_active = TRUE WHERE id = $1 RETURNING *',\n    [req.params.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'Cycle not found.' });\n  res.json(result.rows[0]);\n});\n\n// \u2500\u2500 THRUST AREAS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\n\n// GET /api/thrust-areas\nconst listThrustAreas = asyncHandler(async (req, res) => {\n  const result = await query(\n    'SELECT * FROM thrust_areas WHERE is_active = TRUE ORDER BY name'\n  );\n  res.json(result.rows);\n});\n\n// POST /api/thrust-areas \u2014 Admin only\nconst createThrustArea = asyncHandler(async (req, res) => {\n  const { name, description } = req.body;\n  const result = await query(\n    'INSERT INTO thrust_areas (name, description, created_by) VALUES ($1,$2,$3) RETURNING *',\n    [name, description, req.user.id]\n  );\n  res.status(201).json(result.rows[0]);\n});\n\n// PUT /api/thrust-areas/:id \u2014 Admin only\nconst updateThrustArea = asyncHandler(async (req, res) => {\n  const { name, description, is_active } = req.body;\n  const result = await query(\n    'UPDATE thrust_areas SET name=$1, description=$2, is_active=$3 WHERE id=$4 RETURNING *',\n    [name, description, is_active, req.params.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'Thrust area not found.' });\n  res.json(result.rows[0]);\n});\n\nmodule.exports = {\n  listCycles, getActiveCycle, createCycle, updateCycle, activateCycle,\n  listThrustAreas, createThrustArea, updateThrustArea,\n};\n",
  "src/controllers/goalSheetController.js": "const { query, withTransaction } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\nconst { auditLog } = require('../utils/auditLog');\n\n// GET /api/goal-sheets \u2014 Employee: own sheet; Manager: team sheets; Admin: all\nconst listGoalSheets = asyncHandler(async (req, res) => {\n  const { cycle_id } = req.query;\n  let sql, params;\n\n  if (req.user.role === 'employee') {\n    sql = `\n      SELECT gs.*, gc.name AS cycle_name,\n             u.name AS employee_name, u.department\n      FROM goal_sheets gs\n      JOIN goal_cycles gc ON gc.id = gs.cycle_id\n      JOIN users u ON u.id = gs.employee_id\n      WHERE gs.employee_id = $1\n      ${cycle_id ? 'AND gs.cycle_id = $2' : ''}\n      ORDER BY gs.created_at DESC`;\n    params = cycle_id ? [req.user.id, cycle_id] : [req.user.id];\n  } else if (req.user.role === 'manager') {\n    sql = `\n      SELECT gs.*, gc.name AS cycle_name,\n             u.name AS employee_name, u.department\n      FROM goal_sheets gs\n      JOIN goal_cycles gc ON gc.id = gs.cycle_id\n      JOIN users u ON u.id = gs.employee_id\n      WHERE u.manager_id = $1\n      ${cycle_id ? 'AND gs.cycle_id = $2' : ''}\n      ORDER BY u.name, gs.created_at DESC`;\n    params = cycle_id ? [req.user.id, cycle_id] : [req.user.id];\n  } else {\n    sql = `\n      SELECT gs.*, gc.name AS cycle_name,\n             u.name AS employee_name, u.department,\n             m.name AS manager_name\n      FROM goal_sheets gs\n      JOIN goal_cycles gc ON gc.id = gs.cycle_id\n      JOIN users u ON u.id = gs.employee_id\n      LEFT JOIN users m ON m.id = u.manager_id\n      ${cycle_id ? 'WHERE gs.cycle_id = $1' : ''}\n      ORDER BY u.name, gs.created_at DESC`;\n    params = cycle_id ? [cycle_id] : [];\n  }\n\n  const result = await query(sql, params);\n  res.json(result.rows);\n});\n\n// GET /api/goal-sheets/:id \u2014 with all goals\nconst getGoalSheet = asyncHandler(async (req, res) => {\n  const sheetResult = await query(\n    `SELECT gs.*, gc.name AS cycle_name, gc.q1_opens, gc.q2_opens, gc.q3_opens, gc.q4_opens,\n            u.name AS employee_name, u.email AS employee_email, u.department,\n            m.name AS manager_name, m.email AS manager_email\n     FROM goal_sheets gs\n     JOIN goal_cycles gc ON gc.id = gs.cycle_id\n     JOIN users u ON u.id = gs.employee_id\n     LEFT JOIN users m ON m.id = u.manager_id\n     WHERE gs.id = $1`,\n    [req.params.id]\n  );\n\n  const sheet = sheetResult.rows[0];\n  if (!sheet) return res.status(404).json({ error: 'Goal sheet not found.' });\n\n  // Access control\n  if (req.user.role === 'employee' && sheet.employee_id !== req.user.id) {\n    return res.status(403).json({ error: 'Access denied.' });\n  }\n\n  const goalsResult = await query(\n    `SELECT g.*, ta.name AS thrust_area_name,\n            a_q1.actual_value AS q1_actual, a_q1.actual_date AS q1_actual_date,\n            a_q1.status AS q1_status, a_q1.progress_score AS q1_score,\n            a_q2.actual_value AS q2_actual, a_q2.actual_date AS q2_actual_date,\n            a_q2.status AS q2_status, a_q2.progress_score AS q2_score,\n            a_q3.actual_value AS q3_actual, a_q3.actual_date AS q3_actual_date,\n            a_q3.status AS q3_status, a_q3.progress_score AS q3_score,\n            a_q4.actual_value AS q4_actual, a_q4.actual_date AS q4_actual_date,\n            a_q4.status AS q4_status, a_q4.progress_score AS q4_score\n     FROM goals g\n     LEFT JOIN thrust_areas ta ON ta.id = g.thrust_area_id\n     LEFT JOIN achievements a_q1 ON a_q1.goal_id = g.id AND a_q1.quarter = 'Q1'\n     LEFT JOIN achievements a_q2 ON a_q2.goal_id = g.id AND a_q2.quarter = 'Q2'\n     LEFT JOIN achievements a_q3 ON a_q3.goal_id = g.id AND a_q3.quarter = 'Q3'\n     LEFT JOIN achievements a_q4 ON a_q4.goal_id = g.id AND a_q4.quarter = 'Q4'\n     WHERE g.goal_sheet_id = $1\n     ORDER BY g.created_at`,\n    [req.params.id]\n  );\n\n  res.json({ ...sheet, goals: goalsResult.rows });\n});\n\n// POST /api/goal-sheets \u2014 Employee creates sheet for active cycle\nconst createGoalSheet = asyncHandler(async (req, res) => {\n  const { cycle_id } = req.body;\n\n  const existing = await query(\n    'SELECT id FROM goal_sheets WHERE employee_id=$1 AND cycle_id=$2',\n    [req.user.id, cycle_id]\n  );\n  if (existing.rows.length > 0) {\n    return res.status(409).json({ error: 'Goal sheet already exists for this cycle.' });\n  }\n\n  const result = await query(\n    `INSERT INTO goal_sheets (employee_id, cycle_id, status)\n     VALUES ($1, $2, 'draft') RETURNING *`,\n    [req.user.id, cycle_id]\n  );\n  res.status(201).json(result.rows[0]);\n});\n\n// POST /api/goal-sheets/:id/submit \u2014 Employee submits for approval\nconst submitGoalSheet = asyncHandler(async (req, res) => {\n  const sheet = await query(\n    'SELECT * FROM goal_sheets WHERE id=$1 AND employee_id=$2',\n    [req.params.id, req.user.id]\n  );\n\n  if (!sheet.rows[0]) return res.status(404).json({ error: 'Goal sheet not found.' });\n  if (!['draft', 'returned'].includes(sheet.rows[0].status)) {\n    return res.status(400).json({ error: `Cannot submit a sheet with status \"${sheet.rows[0].status}\".` });\n  }\n\n  // Validate goals exist and weightage rules\n  const goals = await query(\n    'SELECT * FROM goals WHERE goal_sheet_id=$1',\n    [req.params.id]\n  );\n\n  if (goals.rows.length === 0) {\n    return res.status(400).json({ error: 'Cannot submit a goal sheet with no goals.' });\n  }\n  if (goals.rows.length > 8) {\n    return res.status(400).json({ error: 'Maximum 8 goals allowed.' });\n  }\n  for (const g of goals.rows) {\n    if (g.weightage < 10) {\n      return res.status(400).json({ error: `Goal \"${g.title}\" has weightage below minimum 10%.` });\n    }\n  }\n  const total = goals.rows.reduce((s, g) => s + Number(g.weightage), 0);\n  if (Math.abs(total - 100) > 0.01) {\n    return res.status(400).json({ error: `Total weightage must be 100%. Current: ${total}%.` });\n  }\n\n  const result = await query(\n    `UPDATE goal_sheets SET status='submitted', submitted_at=NOW(), total_weightage=$1\n     WHERE id=$2 RETURNING *`,\n    [total, req.params.id]\n  );\n\n  await auditLog({\n    entity_type: 'goal_sheet', entity_id: req.params.id,\n    action: 'submitted', changed_by: req.user.id,\n    new_value: { status: 'submitted' },\n  });\n\n  res.json(result.rows[0]);\n});\n\n// POST /api/goal-sheets/:id/approve \u2014 Manager approves\nconst approveGoalSheet = asyncHandler(async (req, res) => {\n  return withTransaction(async (client) => {\n    const sheet = await client.query(\n      `SELECT gs.*, u.manager_id FROM goal_sheets gs\n       JOIN users u ON u.id = gs.employee_id\n       WHERE gs.id = $1`,\n      [req.params.id]\n    );\n\n    if (!sheet.rows[0]) throw Object.assign(new Error('Goal sheet not found.'), { status: 404 });\n    if (sheet.rows[0].manager_id !== req.user.id && req.user.role !== 'admin') {\n      throw Object.assign(new Error('You are not this employee\\'s manager.'), { status: 403 });\n    }\n    if (sheet.rows[0].status !== 'submitted') {\n      throw Object.assign(new Error(`Sheet is \"${sheet.rows[0].status}\" \u2014 can only approve submitted sheets.`), { status: 400 });\n    }\n\n    // Lock all goals\n    await client.query('UPDATE goals SET is_locked=TRUE WHERE goal_sheet_id=$1', [req.params.id]);\n\n    const result = await client.query(\n      `UPDATE goal_sheets SET status='approved', approved_at=NOW(), approved_by=$1\n       WHERE id=$2 RETURNING *`,\n      [req.user.id, req.params.id]\n    );\n\n    await auditLog({\n      entity_type: 'goal_sheet', entity_id: req.params.id,\n      action: 'approved', changed_by: req.user.id,\n      new_value: { status: 'approved', approved_by: req.user.id },\n      client,\n    });\n\n    return res.json(result.rows[0]);\n  });\n});\n\n// POST /api/goal-sheets/:id/return \u2014 Manager returns for rework\nconst returnGoalSheet = asyncHandler(async (req, res) => {\n  const { return_reason } = req.body;\n  if (!return_reason) return res.status(400).json({ error: 'Return reason is required.' });\n\n  const sheet = await query(\n    `SELECT gs.*, u.manager_id FROM goal_sheets gs\n     JOIN users u ON u.id = gs.employee_id WHERE gs.id=$1`,\n    [req.params.id]\n  );\n  if (!sheet.rows[0]) return res.status(404).json({ error: 'Goal sheet not found.' });\n  if (sheet.rows[0].manager_id !== req.user.id && req.user.role !== 'admin') {\n    return res.status(403).json({ error: 'Access denied.' });\n  }\n\n  const result = await query(\n    `UPDATE goal_sheets SET status='returned', return_reason=$1 WHERE id=$2 RETURNING *`,\n    [return_reason, req.params.id]\n  );\n\n  await auditLog({\n    entity_type: 'goal_sheet', entity_id: req.params.id,\n    action: 'returned', changed_by: req.user.id,\n    new_value: { status: 'returned', return_reason },\n  });\n\n  res.json(result.rows[0]);\n});\n\n// POST /api/goal-sheets/:id/unlock \u2014 Admin only\nconst unlockGoalSheet = asyncHandler(async (req, res) => {\n  await query('UPDATE goals SET is_locked=FALSE WHERE goal_sheet_id=$1', [req.params.id]);\n  const result = await query(\n    `UPDATE goal_sheets SET status='draft' WHERE id=$1 RETURNING *`,\n    [req.params.id]\n  );\n  if (!result.rows[0]) return res.status(404).json({ error: 'Goal sheet not found.' });\n\n  await auditLog({\n    entity_type: 'goal_sheet', entity_id: req.params.id,\n    action: 'unlocked_by_admin', changed_by: req.user.id,\n    notes: req.body.reason || 'Admin unlock',\n  });\n\n  res.json(result.rows[0]);\n});\n\nmodule.exports = {\n  listGoalSheets, getGoalSheet, createGoalSheet,\n  submitGoalSheet, approveGoalSheet, returnGoalSheet, unlockGoalSheet,\n};\n",
  "src/controllers/goalController.js": "const { query, withTransaction } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\nconst { auditLog } = require('../utils/auditLog');\n\n// POST /api/goal-sheets/:sheetId/goals \u2014 Employee adds a goal\nconst addGoal = asyncHandler(async (req, res) => {\n  const { sheetId } = req.params;\n  const { thrust_area_id, title, description, uom_type, target_value, target_date, weightage } = req.body;\n\n  const sheet = await query(\n    'SELECT * FROM goal_sheets WHERE id=$1 AND employee_id=$2',\n    [sheetId, req.user.id]\n  );\n  if (!sheet.rows[0]) return res.status(404).json({ error: 'Goal sheet not found.' });\n  if (sheet.rows[0].status === 'approved') {\n    return res.status(400).json({ error: 'Cannot edit an approved goal sheet.' });\n  }\n\n  // Max 8 goals check\n  const count = await query('SELECT COUNT(*) FROM goals WHERE goal_sheet_id=$1', [sheetId]);\n  if (parseInt(count.rows[0].count) >= 8) {\n    return res.status(400).json({ error: 'Maximum of 8 goals allowed per employee.' });\n  }\n\n  // Min 10% weightage check\n  if (weightage < 10) {\n    return res.status(400).json({ error: 'Minimum weightage per goal is 10%.' });\n  }\n\n  const result = await query(\n    `INSERT INTO goals (goal_sheet_id, thrust_area_id, title, description, uom_type, target_value, target_date, weightage, primary_owner_id)\n     VALUES ($1,$2,$3,$4,$5,$6,$7,$8,$9) RETURNING *`,\n    [sheetId, thrust_area_id, title, description, uom_type, target_value || null, target_date || null, weightage, req.user.id]\n  );\n  res.status(201).json(result.rows[0]);\n});\n\n// PUT /api/goals/:id \u2014 Employee edits own unlocked goal; Manager edits during approval\nconst updateGoal = asyncHandler(async (req, res) => {\n  const goalResult = await query(\n    `SELECT g.*, gs.employee_id, gs.status AS sheet_status, u.manager_id\n     FROM goals g\n     JOIN goal_sheets gs ON gs.id = g.goal_sheet_id\n     JOIN users u ON u.id = gs.employee_id\n     WHERE g.id = $1`,\n    [req.params.id]\n  );\n\n  const goal = goalResult.rows[0];\n  if (!goal) return res.status(404).json({ error: 'Goal not found.' });\n\n  const isOwner = goal.employee_id === req.user.id;\n  const isManager = req.user.role === 'manager' && goal.manager_id === req.user.id;\n  const isAdmin = req.user.role === 'admin';\n\n  if (!isOwner && !isManager && !isAdmin) {\n    return res.status(403).json({ error: 'Access denied.' });\n  }\n  if (goal.is_locked && !isAdmin) {\n    return res.status(400).json({ error: 'Goal is locked after approval. Contact Admin to unlock.' });\n  }\n\n  // Shared goals: recipient can only change weightage\n  if (goal.is_shared && !isAdmin) {\n    const { weightage } = req.body;\n    if (weightage < 10) return res.status(400).json({ error: 'Minimum weightage is 10%.' });\n    const result = await query(\n      'UPDATE goals SET weightage=$1 WHERE id=$2 RETURNING *',\n      [weightage, req.params.id]\n    );\n    return res.json(result.rows[0]);\n  }\n\n  const { thrust_area_id, title, description, uom_type, target_value, target_date, weightage } = req.body;\n\n  if (weightage < 10) return res.status(400).json({ error: 'Minimum weightage is 10%.' });\n\n  const old = goal;\n  const result = await query(\n    `UPDATE goals SET thrust_area_id=$1, title=$2, description=$3, uom_type=$4,\n     target_value=$5, target_date=$6, weightage=$7\n     WHERE id=$8 RETURNING *`,\n    [thrust_area_id, title, description, uom_type, target_value || null, target_date || null, weightage, req.params.id]\n  );\n\n  if (goal.is_locked) {\n    await auditLog({\n      entity_type: 'goal', entity_id: req.params.id,\n      action: 'updated_after_lock', changed_by: req.user.id,\n      old_value: old, new_value: result.rows[0],\n    });\n  }\n\n  res.json(result.rows[0]);\n});\n\n// DELETE /api/goals/:id \u2014 Employee deletes own unlocked goal\nconst deleteGoal = asyncHandler(async (req, res) => {\n  const goalResult = await query(\n    `SELECT g.*, gs.employee_id FROM goals g\n     JOIN goal_sheets gs ON gs.id = g.goal_sheet_id\n     WHERE g.id = $1`,\n    [req.params.id]\n  );\n  const goal = goalResult.rows[0];\n  if (!goal) return res.status(404).json({ error: 'Goal not found.' });\n  if (goal.employee_id !== req.user.id && req.user.role !== 'admin') {\n    return res.status(403).json({ error: 'Access denied.' });\n  }\n  if (goal.is_locked) {\n    return res.status(400).json({ error: 'Cannot delete a locked goal.' });\n  }\n  await query('DELETE FROM goals WHERE id=$1', [req.params.id]);\n  res.json({ message: 'Goal deleted.' });\n});\n\n// POST /api/goals/share \u2014 Admin or Manager pushes shared goal to multiple employees\nconst shareGoal = asyncHandler(async (req, res) => {\n  const { title, description, thrust_area_id, uom_type, target_value, target_date, cycle_id, recipient_ids } = req.body;\n\n  if (!recipient_ids || !Array.isArray(recipient_ids) || recipient_ids.length === 0) {\n    return res.status(400).json({ error: 'recipient_ids must be a non-empty array.' });\n  }\n\n  return withTransaction(async (client) => {\n    const results = [];\n\n    for (const recipientId of recipient_ids) {\n      // Get or create goal sheet for recipient\n      let sheetResult = await client.query(\n        'SELECT id FROM goal_sheets WHERE employee_id=$1 AND cycle_id=$2',\n        [recipientId, cycle_id]\n      );\n      let sheetId;\n      if (sheetResult.rows.length === 0) {\n        const newSheet = await client.query(\n          `INSERT INTO goal_sheets (employee_id, cycle_id, status) VALUES ($1,$2,'draft') RETURNING id`,\n          [recipientId, cycle_id]\n        );\n        sheetId = newSheet.rows[0].id;\n      } else {\n        sheetId = sheetResult.rows[0].id;\n      }\n\n      // Check max 8 goals\n      const count = await client.query('SELECT COUNT(*) FROM goals WHERE goal_sheet_id=$1', [sheetId]);\n      if (parseInt(count.rows[0].count) >= 8) {\n        results.push({ recipient_id: recipientId, error: 'Max goals reached for this employee.' });\n        continue;\n      }\n\n      // Insert shared goal (default weightage 10, recipient can adjust)\n      const goal = await client.query(\n        `INSERT INTO goals (goal_sheet_id, thrust_area_id, title, description, uom_type, target_value, target_date,\n          weightage, is_shared, primary_owner_id)\n         VALUES ($1,$2,$3,$4,$5,$6,$7,10,TRUE,$8) RETURNING id`,\n        [sheetId, thrust_area_id, title, description, uom_type, target_value || null, target_date || null, req.user.id]\n      );\n      results.push({ recipient_id: recipientId, goal_id: goal.rows[0].id, success: true });\n    }\n\n    return res.status(201).json({ shared: results });\n  });\n});\n\nmodule.exports = { addGoal, updateGoal, deleteGoal, shareGoal };\n",
  "src/controllers/achievementController.js": "const { query } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\nconst { computeProgressScore, getCurrentQuarter } = require('../utils/goalUtils');\nconst { auditLog } = require('../utils/auditLog');\n\n// PUT /api/goals/:goalId/achievements/:quarter \u2014 Employee logs achievement\nconst upsertAchievement = asyncHandler(async (req, res) => {\n  const { goalId, quarter } = req.params;\n  const { actual_value, actual_date, status } = req.body;\n\n  if (!['Q1', 'Q2', 'Q3', 'Q4'].includes(quarter)) {\n    return res.status(400).json({ error: 'Quarter must be Q1, Q2, Q3, or Q4.' });\n  }\n\n  // Fetch goal + sheet info\n  const goalResult = await query(\n    `SELECT g.*, gs.employee_id, gs.cycle_id,\n            gc.q1_opens, gc.q2_opens, gc.q3_opens, gc.q4_opens,\n            gs.status AS sheet_status\n     FROM goals g\n     JOIN goal_sheets gs ON gs.id = g.goal_sheet_id\n     JOIN goal_cycles gc ON gc.id = gs.cycle_id\n     WHERE g.id = $1`,\n    [goalId]\n  );\n\n  const goal = goalResult.rows[0];\n  if (!goal) return res.status(404).json({ error: 'Goal not found.' });\n\n  // Access: only the employee who owns the goal sheet\n  if (goal.employee_id !== req.user.id && req.user.role !== 'admin') {\n    return res.status(403).json({ error: 'Access denied.' });\n  }\n\n  if (goal.sheet_status !== 'approved') {\n    return res.status(400).json({ error: 'Goal sheet must be approved before logging achievements.' });\n  }\n\n  // Check if the quarter window is open\n  const currentQ = getCurrentQuarter(goal);\n  if (currentQ === null) {\n    return res.status(400).json({ error: 'Check-in window is not open yet.' });\n  }\n  const qOrder = ['Q1', 'Q2', 'Q3', 'Q4'];\n  if (qOrder.indexOf(quarter) > qOrder.indexOf(currentQ)) {\n    return res.status(400).json({ error: `Quarter ${quarter} window is not open yet.` });\n  }\n\n  // Compute progress score\n  const progress_score = computeProgressScore({\n    uom_type: goal.uom_type,\n    target_value: goal.target_value,\n    target_date: goal.target_date,\n    actual_value,\n    actual_date,\n  });\n\n  // Upsert\n  const result = await query(\n    `INSERT INTO achievements (goal_id, quarter, actual_value, actual_date, status, progress_score, updated_by)\n     VALUES ($1,$2,$3,$4,$5,$6,$7)\n     ON CONFLICT (goal_id, quarter) DO UPDATE\n       SET actual_value=$3, actual_date=$4, status=$5, progress_score=$6,\n           updated_by=$7, updated_at=NOW()\n     RETURNING *`,\n    [goalId, quarter, actual_value ?? null, actual_date ?? null, status, progress_score, req.user.id]\n  );\n\n  // If this is a shared goal, sync the achievement to all recipient goals\n  if (goal.primary_owner_id === req.user.id && goal.is_shared) {\n    const recipients = await query(\n      'SELECT recipient_goal_id FROM shared_goal_recipients WHERE source_goal_id=$1',\n      [goalId]\n    );\n    for (const r of recipients.rows) {\n      await query(\n        `INSERT INTO achievements (goal_id, quarter, actual_value, actual_date, status, progress_score, updated_by)\n         VALUES ($1,$2,$3,$4,$5,$6,$7)\n         ON CONFLICT (goal_id, quarter) DO UPDATE\n           SET actual_value=$3, actual_date=$4, status=$5, progress_score=$6, updated_by=$7, updated_at=NOW()`,\n        [r.recipient_goal_id, quarter, actual_value ?? null, actual_date ?? null, status, progress_score, req.user.id]\n      );\n    }\n  }\n\n  await auditLog({\n    entity_type: 'achievement', entity_id: result.rows[0].id,\n    action: 'upserted', changed_by: req.user.id,\n    new_value: result.rows[0],\n  });\n\n  res.json(result.rows[0]);\n});\n\n// GET /api/goals/:goalId/achievements \u2014 All quarters for a goal\nconst getAchievements = asyncHandler(async (req, res) => {\n  const result = await query(\n    `SELECT a.*, u.name AS updated_by_name\n     FROM achievements a\n     LEFT JOIN users u ON u.id = a.updated_by\n     WHERE a.goal_id = $1 ORDER BY a.quarter`,\n    [req.params.goalId]\n  );\n  res.json(result.rows);\n});\n\nmodule.exports = { upsertAchievement, getAchievements };\n",
  "src/controllers/checkinController.js": "const { query } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\n\n// POST /api/goal-sheets/:sheetId/checkins \u2014 Manager adds/updates check-in comment\nconst upsertCheckin = asyncHandler(async (req, res) => {\n  const { quarter, comment } = req.body;\n  const { sheetId } = req.params;\n\n  if (!['Q1', 'Q2', 'Q3', 'Q4'].includes(quarter)) {\n    return res.status(400).json({ error: 'Quarter must be Q1, Q2, Q3, or Q4.' });\n  }\n  if (!comment || comment.trim().length === 0) {\n    return res.status(400).json({ error: 'Check-in comment is required.' });\n  }\n\n  // Verify manager has access to this sheet\n  const sheetResult = await query(\n    `SELECT gs.*, u.manager_id FROM goal_sheets gs\n     JOIN users u ON u.id = gs.employee_id WHERE gs.id=$1`,\n    [sheetId]\n  );\n  const sheet = sheetResult.rows[0];\n  if (!sheet) return res.status(404).json({ error: 'Goal sheet not found.' });\n\n  if (sheet.manager_id !== req.user.id && req.user.role !== 'admin') {\n    return res.status(403).json({ error: 'Access denied \u2014 you are not this employee\\'s manager.' });\n  }\n  if (sheet.status !== 'approved') {\n    return res.status(400).json({ error: 'Check-ins can only be added to approved goal sheets.' });\n  }\n\n  const result = await query(\n    `INSERT INTO checkins (goal_sheet_id, manager_id, quarter, comment)\n     VALUES ($1,$2,$3,$4)\n     ON CONFLICT (goal_sheet_id, manager_id, quarter) DO UPDATE\n       SET comment=$4, updated_at=NOW()\n     RETURNING *`,\n    [sheetId, req.user.id, quarter, comment.trim()]\n  );\n\n  res.status(201).json(result.rows[0]);\n});\n\n// GET /api/goal-sheets/:sheetId/checkins \u2014 View all check-ins for a sheet\nconst listCheckins = asyncHandler(async (req, res) => {\n  const result = await query(\n    `SELECT c.*, u.name AS manager_name\n     FROM checkins c\n     JOIN users u ON u.id = c.manager_id\n     WHERE c.goal_sheet_id = $1\n     ORDER BY c.quarter, c.created_at`,\n    [req.params.sheetId]\n  );\n  res.json(result.rows);\n});\n\n// GET /api/manager/pending-checkins \u2014 Manager sees which sheets need check-ins this quarter\nconst pendingCheckins = asyncHandler(async (req, res) => {\n  const { quarter } = req.query;\n  if (!quarter) return res.status(400).json({ error: 'quarter query param required.' });\n\n  const result = await query(\n    `SELECT gs.id AS sheet_id, u.name AS employee_name, u.email, u.department,\n            CASE WHEN c.id IS NULL THEN FALSE ELSE TRUE END AS checkin_done\n     FROM goal_sheets gs\n     JOIN users u ON u.id = gs.employee_id\n     LEFT JOIN checkins c ON c.goal_sheet_id = gs.id AND c.manager_id=$1 AND c.quarter=$2\n     WHERE u.manager_id = $1 AND gs.status = 'approved'\n     ORDER BY checkin_done, u.name`,\n    [req.user.id, quarter]\n  );\n  res.json(result.rows);\n});\n\nmodule.exports = { upsertCheckin, listCheckins, pendingCheckins };\n",
  "src/controllers/reportController.js": "const { query } = require('../config/db');\nconst { asyncHandler } = require('../middleware/errorHandler');\n\n// GET /api/reports/achievements?cycle_id= \u2014 Achievement report (CSV-ready)\nconst achievementReport = asyncHandler(async (req, res) => {\n  const { cycle_id, format } = req.query;\n  if (!cycle_id) return res.status(400).json({ error: 'cycle_id is required.' });\n\n  const result = await query(\n    `SELECT\n       u.name AS employee_name, u.email, u.department,\n       m.name AS manager_name,\n       ta.name AS thrust_area,\n       g.title AS goal_title,\n       g.uom_type,\n       g.target_value, g.target_date,\n       g.weightage,\n       a_q1.actual_value AS q1_actual, a_q1.status AS q1_status, a_q1.progress_score AS q1_score,\n       a_q2.actual_value AS q2_actual, a_q2.status AS q2_status, a_q2.progress_score AS q2_score,\n       a_q3.actual_value AS q3_actual, a_q3.status AS q3_status, a_q3.progress_score AS q3_score,\n       a_q4.actual_value AS q4_actual, a_q4.status AS q4_status, a_q4.progress_score AS q4_score\n     FROM goal_sheets gs\n     JOIN users u ON u.id = gs.employee_id\n     LEFT JOIN users m ON m.id = u.manager_id\n     JOIN goals g ON g.goal_sheet_id = gs.id\n     LEFT JOIN thrust_areas ta ON ta.id = g.thrust_area_id\n     LEFT JOIN achievements a_q1 ON a_q1.goal_id = g.id AND a_q1.quarter='Q1'\n     LEFT JOIN achievements a_q2 ON a_q2.goal_id = g.id AND a_q2.quarter='Q2'\n     LEFT JOIN achievements a_q3 ON a_q3.goal_id = g.id AND a_q3.quarter='Q3'\n     LEFT JOIN achievements a_q4 ON a_q4.goal_id = g.id AND a_q4.quarter='Q4'\n     WHERE gs.cycle_id = $1\n     ORDER BY u.name, g.title`,\n    [cycle_id]\n  );\n\n  if (format === 'csv') {\n    const rows = result.rows;\n    if (rows.length === 0) {\n      return res.status(200).send('No data found.');\n    }\n    const headers = Object.keys(rows[0]).join(',');\n    const lines = rows.map(r =>\n      Object.values(r).map(v => (v == null ? '' : `\"${String(v).replace(/\"/g, '\"\"')}\"`)).join(',')\n    );\n    res.setHeader('Content-Type', 'text/csv');\n    res.setHeader('Content-Disposition', `attachment; filename=\"achievement_report_${cycle_id}.csv\"`);\n    return res.send([headers, ...lines].join('\\n'));\n  }\n\n  res.json(result.rows);\n});\n\n// GET /api/reports/completion?cycle_id=&quarter= \u2014 Completion dashboard\nconst completionDashboard = asyncHandler(async (req, res) => {\n  const { cycle_id, quarter } = req.query;\n  if (!cycle_id) return res.status(400).json({ error: 'cycle_id is required.' });\n\n  const employeeCompletion = await query(\n    `SELECT\n       u.id, u.name, u.email, u.department,\n       m.name AS manager_name,\n       gs.status AS sheet_status,\n       gs.submitted_at, gs.approved_at,\n       CASE WHEN $2::text IS NOT NULL THEN\n         (SELECT COUNT(*) FROM achievements a\n          JOIN goals g ON g.id = a.goal_id\n          WHERE g.goal_sheet_id = gs.id AND a.quarter = $2)\n       ELSE NULL END AS achievements_logged,\n       CASE WHEN $2::text IS NOT NULL THEN\n         (SELECT COUNT(*) FROM goals g WHERE g.goal_sheet_id = gs.id)\n       ELSE NULL END AS total_goals\n     FROM users u\n     LEFT JOIN users m ON m.id = u.manager_id\n     LEFT JOIN goal_sheets gs ON gs.employee_id = u.id AND gs.cycle_id = $1\n     WHERE u.role = 'employee' AND u.is_active = TRUE\n     ORDER BY u.name`,\n    [cycle_id, quarter || null]\n  );\n\n  const managerCheckins = quarter ? await query(\n    `SELECT\n       m.id, m.name AS manager_name,\n       COUNT(DISTINCT gs.id) AS total_reports,\n       COUNT(DISTINCT c.goal_sheet_id) AS checkins_done\n     FROM users m\n     JOIN users u ON u.manager_id = m.id\n     JOIN goal_sheets gs ON gs.employee_id = u.id AND gs.cycle_id = $1 AND gs.status = 'approved'\n     LEFT JOIN checkins c ON c.goal_sheet_id = gs.id AND c.manager_id = m.id AND c.quarter = $2\n     WHERE m.role IN ('manager','admin')\n     GROUP BY m.id, m.name\n     ORDER BY m.name`,\n    [cycle_id, quarter]\n  ) : { rows: [] };\n\n  res.json({\n    employees: employeeCompletion.rows,\n    manager_checkins: managerCheckins.rows,\n  });\n});\n\n// GET /api/reports/audit?entity_id= \u2014 Audit trail (Admin only)\nconst auditTrail = asyncHandler(async (req, res) => {\n  const { entity_id, entity_type, from_date, to_date } = req.query;\n\n  let sql = `\n    SELECT al.*, u.name AS changed_by_name, u.email AS changed_by_email\n    FROM audit_logs al\n    JOIN users u ON u.id = al.changed_by\n    WHERE 1=1\n  `;\n  const params = [];\n\n  if (entity_id) { params.push(entity_id); sql += ` AND al.entity_id = $${params.length}`; }\n  if (entity_type) { params.push(entity_type); sql += ` AND al.entity_type = $${params.length}`; }\n  if (from_date) { params.push(from_date); sql += ` AND al.created_at >= $${params.length}`; }\n  if (to_date) { params.push(to_date); sql += ` AND al.created_at <= $${params.length}`; }\n\n  sql += ' ORDER BY al.created_at DESC LIMIT 500';\n\n  const result = await query(sql, params);\n  res.json(result.rows);\n});\n\n// GET /api/reports/analytics?cycle_id= \u2014 Bonus: analytics summary\nconst analytics = asyncHandler(async (req, res) => {\n  const { cycle_id } = req.query;\n  if (!cycle_id) return res.status(400).json({ error: 'cycle_id is required.' });\n\n  const [byDept, byThrust, byUom, managerEffectiveness] = await Promise.all([\n    // Achievement by department\n    query(\n      `SELECT u.department,\n              COUNT(DISTINCT gs.employee_id) AS employees,\n              AVG(a.progress_score) AS avg_score\n       FROM goal_sheets gs\n       JOIN users u ON u.id = gs.employee_id\n       JOIN goals g ON g.goal_sheet_id = gs.id\n       LEFT JOIN achievements a ON a.goal_id = g.id\n       WHERE gs.cycle_id=$1 GROUP BY u.department ORDER BY u.department`,\n      [cycle_id]\n    ),\n    // By thrust area\n    query(\n      `SELECT ta.name AS thrust_area, COUNT(g.id) AS goal_count,\n              AVG(a.progress_score) AS avg_score\n       FROM goals g\n       JOIN goal_sheets gs ON gs.id = g.goal_sheet_id\n       LEFT JOIN thrust_areas ta ON ta.id = g.thrust_area_id\n       LEFT JOIN achievements a ON a.goal_id = g.id\n       WHERE gs.cycle_id=$1 GROUP BY ta.name ORDER BY goal_count DESC`,\n      [cycle_id]\n    ),\n    // By UoM type\n    query(\n      `SELECT g.uom_type, COUNT(g.id) AS goal_count, AVG(a.progress_score) AS avg_score\n       FROM goals g\n       JOIN goal_sheets gs ON gs.id = g.goal_sheet_id\n       LEFT JOIN achievements a ON a.goal_id = g.id\n       WHERE gs.cycle_id=$1 GROUP BY g.uom_type`,\n      [cycle_id]\n    ),\n    // Manager check-in effectiveness (all quarters combined)\n    query(\n      `SELECT m.name AS manager, m.id,\n              COUNT(DISTINCT gs.id) AS total_reports,\n              COUNT(DISTINCT c.id) AS checkins_done,\n              ROUND(COUNT(DISTINCT c.id)::numeric / NULLIF(COUNT(DISTINCT gs.id),0) * 100, 1) AS completion_pct\n       FROM users m\n       JOIN users u ON u.manager_id = m.id\n       JOIN goal_sheets gs ON gs.employee_id = u.id AND gs.cycle_id=$1 AND gs.status='approved'\n       LEFT JOIN checkins c ON c.goal_sheet_id = gs.id AND c.manager_id = m.id\n       WHERE m.role IN ('manager','admin')\n       GROUP BY m.id, m.name ORDER BY completion_pct DESC`,\n      [cycle_id]\n    ),\n  ]);\n\n  res.json({\n    by_department: byDept.rows,\n    by_thrust_area: byThrust.rows,\n    by_uom_type: byUom.rows,\n    manager_effectiveness: managerEffectiveness.rows,\n  });\n});\n\nmodule.exports = { achievementReport, completionDashboard, auditTrail, analytics };\n",
  "src/middleware/auth.js": "const jwt = require('jsonwebtoken');\n\nconst authenticate = (req, res, next) => {\n  const authHeader = req.headers.authorization;\n  if (!authHeader || !authHeader.startsWith('Bearer ')) {\n    return res.status(401).json({ error: 'Missing or invalid authorization header' });\n  }\n\n  const token = authHeader.split(' ')[1];\n  try {\n    const decoded = jwt.verify(token, process.env.JWT_SECRET);\n    req.user = decoded; // { id, email, role, name }\n    next();\n  } catch (err) {\n    return res.status(401).json({ error: 'Token expired or invalid' });\n  }\n};\n\n// Role-based access guard\nconst authorize = (...roles) => (req, res, next) => {\n  if (!roles.includes(req.user.role)) {\n    return res.status(403).json({ error: `Access denied. Required role(s): ${roles.join(', ')}` });\n  }\n  next();\n};\n\nmodule.exports = { authenticate, authorize };\n",
  "src/middleware/errorHandler.js": "// Wraps async route handlers to forward errors to Express error handler\nconst asyncHandler = (fn) => (req, res, next) => {\n  Promise.resolve(fn(req, res, next)).catch(next);\n};\n\n// Central error handler \u2014 register as last middleware in app.js\nconst errorHandler = (err, req, res, next) => {\n  console.error(`[ERROR] ${req.method} ${req.path}:`, err.message);\n\n  if (err.code === '23505') {\n    // PostgreSQL unique violation\n    return res.status(409).json({ error: 'Duplicate entry \u2014 record already exists' });\n  }\n  if (err.code === '23503') {\n    // Foreign key violation\n    return res.status(400).json({ error: 'Referenced record does not exist' });\n  }\n\n  const status = err.status || err.statusCode || 500;\n  res.status(status).json({\n    error: err.message || 'Internal server error',\n    ...(process.env.NODE_ENV === 'development' && { stack: err.stack }),\n  });\n};\n\nconst notFound = (req, res) => {\n  res.status(404).json({ error: `Route ${req.method} ${req.path} not found` });\n};\n\nmodule.exports = { asyncHandler, errorHandler, notFound };\n",
  "src/routes/index.js": "const express = require('express');\nconst router = express.Router();\nconst { authenticate, authorize } = require('../middleware/auth');\n\n// Controllers\nconst auth = require('../controllers/authController');\nconst users = require('../controllers/userController');\nconst cycles = require('../controllers/cycleController');\nconst sheets = require('../controllers/goalSheetController');\nconst goals = require('../controllers/goalController');\nconst achievements = require('../controllers/achievementController');\nconst checkins = require('../controllers/checkinController');\nconst reports = require('../controllers/reportController');\n\n// \u2500\u2500 AUTH \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.post('/auth/register', auth.register);\nrouter.post('/auth/login', auth.login);\nrouter.get('/auth/me', authenticate, auth.me);\n\n// \u2500\u2500 USERS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/users', authenticate, authorize('admin', 'manager'), users.listUsers);\nrouter.get('/users/managers', authenticate, users.listManagers);\nrouter.get('/users/:id', authenticate, users.getUser);\nrouter.put('/users/:id', authenticate, authorize('admin'), users.updateUser);\nrouter.post('/users/:id/reset-password', authenticate, authorize('admin'), users.resetPassword);\n\n// \u2500\u2500 CYCLES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/cycles', authenticate, cycles.listCycles);\nrouter.get('/cycles/active', authenticate, cycles.getActiveCycle);\nrouter.post('/cycles', authenticate, authorize('admin'), cycles.createCycle);\nrouter.put('/cycles/:id', authenticate, authorize('admin'), cycles.updateCycle);\nrouter.post('/cycles/:id/activate', authenticate, authorize('admin'), cycles.activateCycle);\n\n// \u2500\u2500 THRUST AREAS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/thrust-areas', authenticate, cycles.listThrustAreas);\nrouter.post('/thrust-areas', authenticate, authorize('admin'), cycles.createThrustArea);\nrouter.put('/thrust-areas/:id', authenticate, authorize('admin'), cycles.updateThrustArea);\n\n// \u2500\u2500 GOAL SHEETS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/goal-sheets', authenticate, sheets.listGoalSheets);\nrouter.post('/goal-sheets', authenticate, authorize('employee'), sheets.createGoalSheet);\nrouter.get('/goal-sheets/:id', authenticate, sheets.getGoalSheet);\nrouter.post('/goal-sheets/:id/submit', authenticate, authorize('employee'), sheets.submitGoalSheet);\nrouter.post('/goal-sheets/:id/approve', authenticate, authorize('manager', 'admin'), sheets.approveGoalSheet);\nrouter.post('/goal-sheets/:id/return', authenticate, authorize('manager', 'admin'), sheets.returnGoalSheet);\nrouter.post('/goal-sheets/:id/unlock', authenticate, authorize('admin'), sheets.unlockGoalSheet);\n\n// \u2500\u2500 GOALS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.post('/goal-sheets/:sheetId/goals', authenticate, authorize('employee'), goals.addGoal);\nrouter.put('/goals/:id', authenticate, goals.updateGoal);\nrouter.delete('/goals/:id', authenticate, goals.deleteGoal);\nrouter.post('/goals/share', authenticate, authorize('admin', 'manager'), goals.shareGoal);\n\n// \u2500\u2500 ACHIEVEMENTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/goals/:goalId/achievements', authenticate, achievements.getAchievements);\nrouter.put('/goals/:goalId/achievements/:quarter', authenticate, authorize('employee', 'admin'), achievements.upsertAchievement);\n\n// \u2500\u2500 CHECK-INS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/goal-sheets/:sheetId/checkins', authenticate, checkins.listCheckins);\nrouter.post('/goal-sheets/:sheetId/checkins', authenticate, authorize('manager', 'admin'), checkins.upsertCheckin);\nrouter.get('/manager/pending-checkins', authenticate, authorize('manager', 'admin'), checkins.pendingCheckins);\n\n// \u2500\u2500 REPORTS \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\nrouter.get('/reports/achievements', authenticate, authorize('admin', 'manager'), reports.achievementReport);\nrouter.get('/reports/completion', authenticate, authorize('admin', 'manager'), reports.completionDashboard);\nrouter.get('/reports/audit', authenticate, authorize('admin'), reports.auditTrail);\nrouter.get('/reports/analytics', authenticate, authorize('admin', 'manager'), reports.analytics);\n\nmodule.exports = router;\n",
  "src/app.js": "require('dotenv').config();\nconst express = require('express');\nconst cors = require('cors');\nconst helmet = require('helmet');\n\nconst routes = require('./routes/index');\nconst { errorHandler, notFound } = require('./middleware/errorHandler');\n\nconst app = express();\n\n// \u2500\u2500 SECURITY & PARSING \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\napp.use(helmet());\napp.use(cors({\n  origin: process.env.CORS_ORIGIN || '*',\n  methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],\n  allowedHeaders: ['Content-Type', 'Authorization'],\n}));\napp.use(express.json({ limit: '5mb' }));\napp.use(express.urlencoded({ extended: true }));\n\n// \u2500\u2500 HEALTH CHECK \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\napp.get('/health', (req, res) => {\n  res.json({ status: 'ok', timestamp: new Date().toISOString(), env: process.env.NODE_ENV });\n});\n\n// \u2500\u2500 API ROUTES \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\napp.use('/api', routes);\n\n// \u2500\u2500 ERROR HANDLING \u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\u2500\napp.use(notFound);\napp.use(errorHandler);\n\nconst PORT = process.env.PORT || 3000;\napp.listen(PORT, () => {\n  console.log(`\\n\ud83d\ude80 AtomQuest API running on port ${PORT}`);\n  console.log(`   Environment : ${process.env.NODE_ENV || 'development'}`);\n  console.log(`   Health check: http://localhost:${PORT}/health\\n`);\n});\n\nmodule.exports = app;\n",
  "src/utils/goalUtils.js": "/**\n * Computes the progress score (0\u20131) for a goal based on UoM type.\n * Returns null if insufficient data.\n */\nconst computeProgressScore = ({ uom_type, target_value, target_date, actual_value, actual_date }) => {\n  switch (uom_type) {\n    case 'numeric_min': {\n      // Higher is better (e.g. Sales Revenue) \u2192 Achievement / Target\n      if (!target_value || target_value === 0 || actual_value == null) return null;\n      return Math.min(actual_value / target_value, 2); // cap at 200%\n    }\n    case 'numeric_max': {\n      // Lower is better (e.g. TAT, Cost) \u2192 Target / Achievement\n      if (!target_value || actual_value == null || actual_value === 0) return null;\n      return Math.min(target_value / actual_value, 2);\n    }\n    case 'timeline': {\n      // Date-based: completed on or before deadline = 100%, else proportional\n      if (!target_date || !actual_date) return null;\n      const deadline = new Date(target_date);\n      const completed = new Date(actual_date);\n      if (completed <= deadline) return 1;\n      // overdue \u2014 return 0 (or you could do partial credit logic)\n      return 0;\n    }\n    case 'zero': {\n      // Zero = success (e.g. safety incidents)\n      if (actual_value == null) return null;\n      return actual_value === 0 ? 1 : 0;\n    }\n    default:\n      return null;\n  }\n};\n\n/**\n * Validates goal weightage business rules for a list of goals.\n * Returns { valid: bool, errors: [] }\n */\nconst validateWeightage = (goals) => {\n  const errors = [];\n\n  if (goals.length > 8) {\n    errors.push(`Maximum 8 goals allowed per employee. Got ${goals.length}.`);\n  }\n\n  for (const g of goals) {\n    if (g.weightage < 10) {\n      errors.push(`Goal \"${g.title}\" has weightage ${g.weightage}% \u2014 minimum is 10%.`);\n    }\n  }\n\n  const total = goals.reduce((sum, g) => sum + Number(g.weightage), 0);\n  if (Math.abs(total - 100) > 0.01) {\n    errors.push(`Total weightage must equal 100%. Current total: ${total}%.`);\n  }\n\n  return { valid: errors.length === 0, errors };\n};\n\n/**\n * Determines which quarter is currently active for check-ins.\n */\nconst getCurrentQuarter = (cycle) => {\n  const now = new Date();\n  const toDate = (d) => d ? new Date(d) : null;\n\n  if (toDate(cycle.q4_opens) && now >= toDate(cycle.q4_opens)) return 'Q4';\n  if (toDate(cycle.q3_opens) && now >= toDate(cycle.q3_opens)) return 'Q3';\n  if (toDate(cycle.q2_opens) && now >= toDate(cycle.q2_opens)) return 'Q2';\n  if (toDate(cycle.q1_opens) && now >= toDate(cycle.q1_opens)) return 'Q1';\n  return null; // goal setting phase\n};\n\nmodule.exports = { computeProgressScore, validateWeightage, getCurrentQuarter };\n",
  "src/utils/auditLog.js": "const { query } = require('../config/db');\n\nconst auditLog = async ({ entity_type, entity_id, action, changed_by, old_value, new_value, notes, client }) => {\n  const q = `\n    INSERT INTO audit_logs (entity_type, entity_id, action, changed_by, old_value, new_value, notes)\n    VALUES ($1, $2, $3, $4, $5, $6, $7)\n  `;\n  const params = [\n    entity_type,\n    entity_id,\n    action,\n    changed_by,\n    old_value ? JSON.stringify(old_value) : null,\n    new_value ? JSON.stringify(new_value) : null,\n    notes || null,\n  ];\n  if (client) {\n    return client.query(q, params); // use existing transaction client\n  }\n  return query(q, params);\n};\n\nmodule.exports = { auditLog };\n",
  "src/config/db.js": "const { Pool } = require('pg');\n\nconst pool = new Pool({\n  host: process.env.DB_HOST || 'localhost',\n  port: process.env.DB_PORT || 5432,\n  database: process.env.DB_NAME || 'atomquest',\n  user: process.env.DB_USER || 'postgres',\n  password: process.env.DB_PASSWORD || 'postgres',\n  max: 20,\n  idleTimeoutMillis: 30000,\n  connectionTimeoutMillis: 2000,\n});\n\npool.on('error', (err) => {\n  console.error('Unexpected PostgreSQL client error', err);\n});\n\nconst query = (text, params) => pool.query(text, params);\n\nconst getClient = () => pool.connect();\n\n// Transaction helper\nconst withTransaction = async (callback) => {\n  const client = await pool.connect();\n  try {\n    await client.query('BEGIN');\n    const result = await callback(client);\n    await client.query('COMMIT');\n    return result;\n  } catch (err) {\n    await client.query('ROLLBACK');\n    throw err;\n  } finally {\n    client.release();\n  }\n};\n\nmodule.exports = { query, getClient, withTransaction, pool };\n",
  "src/config/seed.js": "/**\n * Seed script \u2014 creates demo users, an active cycle, and thrust areas.\n * Run: node src/config/seed.js\n */\nrequire('dotenv').config();\nconst { query, pool } = require('./db');\nconst bcrypt = require('bcryptjs');\n\nconst seed = async () => {\n  console.log('\ud83c\udf31 Seeding demo data...');\n\n  // Demo users\n  const password = await bcrypt.hash('Password123!', 12);\n\n  // Admin\n  const admin = await query(\n    `INSERT INTO users (name, email, password_hash, role, department)\n     VALUES ('Admin User', 'admin@atomquest.com', $1, 'admin', 'HR')\n     ON CONFLICT (email) DO UPDATE SET name=EXCLUDED.name RETURNING id, name, email`,\n    [password]\n  );\n\n  // Manager\n  const manager = await query(\n    `INSERT INTO users (name, email, password_hash, role, department)\n     VALUES ('Manager One', 'manager@atomquest.com', $1, 'manager', 'Engineering')\n     ON CONFLICT (email) DO UPDATE SET name=EXCLUDED.name RETURNING id, name, email`,\n    [password]\n  );\n\n  // Employee\n  await query(\n    `INSERT INTO users (name, email, password_hash, role, department, manager_id)\n     VALUES ('Employee One', 'employee@atomquest.com', $1, 'employee', 'Engineering', $2)\n     ON CONFLICT (email) DO UPDATE SET name=EXCLUDED.name`,\n    [password, manager.rows[0].id]\n  );\n\n  // Thrust Areas\n  const thrustAreas = ['Revenue Growth', 'Customer Satisfaction', 'Operational Excellence', 'People & Culture', 'Safety & Compliance'];\n  for (const name of thrustAreas) {\n    await query(\n      `INSERT INTO thrust_areas (name, created_by) VALUES ($1, $2) ON CONFLICT DO NOTHING`,\n      [name, admin.rows[0].id]\n    );\n  }\n\n  // Active Goal Cycle\n  await query(`UPDATE goal_cycles SET is_active=FALSE`);\n  await query(\n    `INSERT INTO goal_cycles (name, start_date, end_date, goal_setting_opens, q1_opens, q2_opens, q3_opens, q4_opens, is_active, created_by)\n     VALUES ('FY 2025-26', '2025-04-01', '2026-03-31', '2025-05-01', '2025-07-01', '2025-10-01', '2026-01-01', '2026-03-01', TRUE, $1)\n     ON CONFLICT DO NOTHING`,\n    [admin.rows[0].id]\n  );\n\n  console.log('\\n\u2705 Seed complete! Demo credentials:');\n  console.log('   Admin   \u2192 admin@atomquest.com    / Password123!');\n  console.log('   Manager \u2192 manager@atomquest.com  / Password123!');\n  console.log('   Employee\u2192 employee@atomquest.com / Password123!\\n');\n\n  await pool.end();\n};\n\nseed().catch((err) => { console.error('Seed failed:', err); process.exit(1); });\n"
};

for (const [filePath, content] of Object.entries(files)) {
  const dir = path.dirname(filePath);
  fs.mkdirSync(dir, { recursive: true });
  fs.writeFileSync(filePath, content, { encoding: 'utf8' });
  console.log('  wrote:', filePath);
}
console.log('\n✅ All files fixed! Now run: npm run dev');
